# functions.tf - Manages Cloud Functions deployment

# Step 1: Package the legacy Cloud Functions source code into a zip archive.
# This data source reads the contents of the ../functions directory,
# zips them, and makes the archive available to Terraform.
# NOTE: You must run `npm run build` in the `functions` directory before
# running `terraform apply` to ensure the `lib` directory is up-to-date.
data "archive_file" "functions_source" {
  type        = "zip"
  source_dir  = "${path.module}/../functions"
  output_path = "${path.module}/.terraform/source.zip"

  # Exclude files not needed for the production deployment to keep the zip small.
  excludes = [
    "node_modules",
    ".git",
    ".idea",
    ".vscode",
    "*.log",
    ".eslintrc.js",
    "tsconfig.dev.json"
  ]
}

# Step 2: Package the new client-onboarding function source code.
# This follows the new microservices architecture by packaging each service independently.
data "archive_file" "onboarding_function_source" {
  type        = "zip"
  source_dir  = "${path.module}/../services/client-onboarding"
  output_path = "${path.module}/.terraform/onboarding-source.zip"

  # Exclude files not needed for the production deployment.
  excludes = [
    "node_modules",
    ".git",
    ".idea",
    ".vscode",
    "*.log"
  ]
}

# Step 3: Upload the zipped source code archives to the Cloud Storage bucket.
resource "google_storage_bucket_object" "functions_source_archive" {
  name   = "source.zip#${data.archive_file.functions_source.output_md5}"
  bucket = google_storage_bucket.functions_source_bucket.name
  source = data.archive_file.functions_source.output_path
}

resource "google_storage_bucket_object" "onboarding_source_archive" {
  name   = "onboarding-source.zip#${data.archive_file.onboarding_function_source.output_md5}"
  bucket = google_storage_bucket.functions_source_bucket.name
  source = data.archive_file.onboarding_function_source.output_path
}

# Step 4: Define the Cloud Function resource for the regulatory monitor.
resource "google_cloudfunctions2_function" "regulatory_monitor" {
  project  = var.project_id
  name     = "regulatory-monitor"
  location = var.location

  build_config {
    runtime     = "nodejs22"
    entry_point = "checkRegulatoryChanges"
    service_account = google_service_account.functions_service_account.name
    source {
      storage_source {
        bucket = google_storage_bucket.functions_source_bucket.name
        object = google_storage_bucket_object.functions_source_archive.name
      }
    }
  }

  service_config {
    max_instance_count    = 1
    min_instance_count    = 0
    available_memory      = "1Gi"
    timeout_seconds       = 120
    service_account_email = google_service_account.functions_service_account.email
  }

  event_trigger {
    trigger_region = var.location
    event_type     = "google.cloud.pubsub.topic.v1.messagePublished"
    pubsub_topic   = google_pubsub_topic.regulatory_monitor_topic.id
    retry_policy   = "RETRY_POLICY_RETRY"
  }

  depends_on = [
    google_project_service.project_apis,
    google_project_service.eventarc # Explicitly depend on the Eventarc API
  ]
}

# Step 5: Define the Cloud Function resource for the transaction processor.
# This ensures our IaC matches the application code, resolving deployment conflicts.
resource "google_cloudfunctions2_function" "transaction_processor" {
  project  = var.project_id
  name     = "process-transaction-file" # A URL-friendly name
  location = var.location

  build_config {
    runtime     = "nodejs22"
    entry_point = "processTransactionFile" # Matches the export in index.ts
    # Use the dedicated service account for the build process for consistency and security.
    service_account = google_service_account.functions_service_account.name
    source {
      storage_source {
        bucket = google_storage_bucket.functions_source_bucket.name
        object = google_storage_bucket_object.functions_source_archive.name
      }
    }
  }

  service_config {
    max_instance_count    = 5 # Can handle more concurrent uploads
    min_instance_count    = 0
    available_memory      = "512Mi"
    timeout_seconds       = 60
    # Use the same dedicated service account for consistency and security
    service_account_email = google_service_account.functions_service_account.email
  }

  event_trigger {
    trigger_region = var.location
    event_type     = "google.cloud.storage.object.v1.finalized"
    retry_policy   = "RETRY_POLICY_RETRY"
    event_filters {
      attribute = "bucket"
      value     = google_storage_bucket.transaction_uploads.name
    }
  }

  depends_on = [
    google_project_service.project_apis,
    google_project_service.eventarc # Explicitly depend on the Eventarc API
  ]
}

# Step 6: Define the Cloud Function resource for the new client onboarding workflow.
resource "google_cloudfunctions2_function" "onboard_client_function" {
  project  = var.project_id
  name     = "onboard-client-function" # A URL-friendly name
  location = var.location

  build_config {
    runtime         = "nodejs22"
    entry_point     = "onboardClientFunction" # Matches the export in the new service
    service_account = google_service_account.functions_service_account.name
    source {
      storage_source {
        bucket = google_storage_bucket.functions_source_bucket.name
        object = google_storage_bucket_object.onboarding_source_archive.name
      }
    }
  }

  service_config {
    max_instance_count    = 3
    min_instance_count    = 0
    available_memory      = "256Mi"
    timeout_seconds       = 60
    # Use the dedicated service account for all application logic.
    service_account_email = google_service_account.functions_service_account.email
    # All onCall functions are HTTPS-triggered. This allows public access
    # to the function URL, while the Firebase SDK handles authentication.
    ingress_settings = "ALLOW_ALL"
  }

  depends_on = [
    # Ensure core APIs are enabled before attempting to deploy the function.
    google_project_service.project_apis,
    google_project_service.eventarc
  ]
}

# Allow unauthenticated invocations for the HTTPS-triggered onCall function.
# The Firebase SDK on the client and in the function code will handle user authentication.
resource "google_cloud_run_service_iam_member" "onboard_client_invoker" {
  location = google_cloudfunctions2_function.onboard_client_function.location
  project  = google_cloudfunctions2_function.onboard_client_function.project
  service  = google_cloudfunctions2_function.onboard_client_function.name
  role     = "roles/run.invoker"
  member   = "allUsers"
}

import React, { useState } from 'react';
// Assumes you have firebase configured and exported from a file like './firebase'
import { getFunctions, httpsCallable } from 'firebase/functions';

// --- Mock Firebase for demonstration ---
// const mockHttpsCallable = (data: any) => {
//   console.log('Calling mock onboardClientFunction with:', data);
//   return new Promise((resolve) => {
//     setTimeout(() => {
//       resolve({ data: { status: 'success', message: 'Client onboarded!', clientId: 'mockClientId123' } });
//     }, 1500);
//   });
// };
const functions = getFunctions();
const onboardClientFunction = httpsCallable(functions, 'onboardClientFunction');
// const onboardClientFunction = mockHttpsCallable;
// --- End Mock ---

// Define a type for the Beneficial Owner data structure for type safety.
type BeneficialOwner = {
  fullName: string;
  residentialAddress: string;
  serviceAddress: string;
  dateOfBirth: string;
  nationality: string;
  nationalIdNumber: string;
  taxIdNumber: string;
  dateBecameBo: string;
};

const initialBoState: BeneficialOwner = {
  fullName: '',
  residentialAddress: '',
  serviceAddress: '',
  dateOfBirth: '',
  nationality: '',
  nationalIdNumber: '',
  taxIdNumber: '',
  dateBecameBo: '',
};

export const OnboardingWizard = () => {
  const [step, setStep] = useState(1);
  const [clientName, setClientName] = useState('');
  const [beneficialOwners, setBeneficialOwners] = useState<BeneficialOwner[]>([initialBoState]);
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [successMessage, setSuccessMessage] = useState<string | null>(null);

  const handleAddBo = () => {
    setBeneficialOwners([...beneficialOwners, { ...initialBoState }]);
  };

  const handleBoChange = (index: number, event: React.ChangeEvent<HTMLInputElement>) => {
    const newBos = [...beneficialOwners];
    newBos[index] = { ...newBos[index], [event.target.name]: event.target.value };
    setBeneficialOwners(newBos);
  };

  const handleSubmit = async (event: React.FormEvent) => {
    event.preventDefault();
    setIsLoading(true);
    setError(null);
    setSuccessMessage(null);

    try {
      const payload = {
        clientName,
        beneficialOwners,
      };
      // In a real app, you would use the actual firebase function call
      const result: any = await onboardClientFunction(payload);
      setSuccessMessage(result.data.message);
      setStep(3); // Move to success step
    } catch (err: any) {
      setError(err.message || 'An unknown error occurred.');
    } finally {
      setIsLoading(false);
    }
  };

  const renderStep1 = () => (
    <div>
      <h2>Step 1: Client Information</h2>
      <label>
        Client Company Name:
        <input
          type="text"
          value={clientName}
          onChange={(e) => setClientName(e.target.value)}
          required
        />
      </label>
      <hr />
      <h2>Beneficial Owners</h2>
      {beneficialOwners.map((bo, index) => (
        <div key={index} style={{ border: '1px solid #ccc', padding: '10px', marginBottom: '10px' }}>
          <h4>Beneficial Owner {index + 1}</h4>
          <input name="fullName" value={bo.fullName} onChange={(e) => handleBoChange(index, e)} placeholder="Full Name" required />
          <input name="residentialAddress" value={bo.residentialAddress} onChange={(e) => handleBoChange(index, e)} placeholder="Residential Address" required />
          <input name="serviceAddress" value={bo.serviceAddress} onChange={(e) => handleBoChange(index, e)} placeholder="Service Address" required />
          <label>Date of Birth: <input name="dateOfBirth" type="date" value={bo.dateOfBirth} onChange={(e) => handleBoChange(index, e)} required /></label>
          <input name="nationality" value={bo.nationality} onChange={(e) => handleBoChange(index, e)} placeholder="Nationality (e.g., SC)" maxLength={2} required />
          <input name="nationalIdNumber" value={bo.nationalIdNumber} onChange={(e) => handleBoChange(index, e)} placeholder="National ID Number" required />
          <input name="taxIdNumber" value={bo.taxIdNumber} onChange={(e) => handleBoChange(index, e)} placeholder="Tax ID Number" required />
          <label>Date Became BO: <input name="dateBecameBo" type="date" value={bo.dateBecameBo} onChange={(e) => handleBoChange(index, e)} required /></label>
        </div>
      ))}
      <button type="button" onClick={handleAddBo}>Add Another Beneficial Owner</button>
      <br />
      <button type="button" onClick={() => setStep(2)} disabled={!clientName}>Next: Review</button>
    </div>
  );

  const renderStep2 = () => (
    <div>
      <h2>Step 2: Review and Submit</h2>
      <h3>Client: {clientName}</h3>
      <h4>Beneficial Owners:</h4>
      <ul>
        {beneficialOwners.map((bo, index) => (
          <li key={index}>{bo.fullName}</li>
        ))}
      </ul>
      <button type="button" onClick={() => setStep(1)}>Back to Edit</button>
      <button type="submit" disabled={isLoading}>
        {isLoading ? 'Submitting...' : 'Submit Onboarding Data'}
      </button>
    </div>
  );

  const renderStep3 = () => (
    <div>
      <h2>Onboarding Complete!</h2>
      <p>{successMessage}</p>
      <button onClick={() => {
        setStep(1);
        setClientName('');
        setBeneficialOwners([initialBoState]);
        setSuccessMessage(null);
      }}>
        Onboard Another Client
      </button>
    </div>
  );

  return (
    <div style={{ fontFamily: 'sans-serif', maxWidth: '600px', margin: 'auto' }}>
      <h1>Client Onboarding Wizard</h1>
      <form onSubmit={handleSubmit}>
        {step === 1 && renderStep1()}
        {step === 2 && renderStep2()}
        {error && <p style={{ color: 'red' }}>Error: {error}</p>}
      </form>
      {step === 3 && renderStep3()}
    </div>
  );
};

export default OnboardingWizard;
